import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.railway.com/reference/public-api";
const PLACEHOLDER_VALUE = "c0ffee5a-fe10-ca1c-0ffe-e5afe10ca1c0";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Railway public API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:railway",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const railwayFirewall = {",
    '  name: "railway",',
    '  description: "Railway public API (account/workspace token)",',
    "  placeholders: {",
    `    RAILWAY_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://backboard.railway.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.RAILWAY_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Railway firewall config...");
  const ts = generateTypeScript();
  writeOutput("railway", ts, import.meta.dirname);
}
